// Check if AI extraction succeeded
if ($json.error) {
	return {
		json: {
			error_occurred: true,
			error_type: "AI_EXTRACTION_FAILED",
			error_message: $json.error.message || "AI extraction failed",
			timestamp: new Date().toISOString()
		}
	};
}

let data;
try {
	data = typeof $json.output === 'string' ? JSON.parse($json.output) : $json.output;
} catch (e) {
	return {
		json: {
			error_occurred: true,
			error_type: "JSON_PARSE_ERROR",
			error_message: e.message,
			timestamp: new Date().toISOString()
		}
	};
}

// Validation Logic
const required = ['vendor_name', 'total_amount', 'invoice_date'];
const missing = required.filter(field => !data[field]);

if (missing.length > 0) {
	return {
		json: {
			error_occurred: true,
			error_type: "MISSING_FIELDS",
			error_message: `Missing: ${missing.join(', ')}`,
			extracted_data: data,
			timestamp: new Date().toISOString()
		}
	};
}

// Amount Validation
if (isNaN(parseFloat(data.total_amount))) {
	return {
		json: {
			error_occurred: true,
			error_type: "INVALID_AMOUNT",
			error_message: "Total Amount is not a number",
			extracted_data: data,
			timestamp: new Date().toISOString()
		}
	};
}

return {
	json: {
		error_occurred: false,
		validated_data: data
	}
};

const data = $json.validated_data || {};

// Helper: normalize text
const norm = txt => (txt || "").toString().toLowerCase().trim();

// Combine searchable text fields
const combinedText = [
  norm(data.vendor_name),
  norm(data.merchant_name),
  norm(data.description),
  norm(data.notes),
  norm(data.expense_type),
].filter(Boolean).join(" ");

// Category rules (SIMPLE NAMES)
const CATEGORY_MAP = [
  { keys: ["aws", "amazon", "amazon web services", "google cloud", "gcp", "digitalocean", "azure", "cloudflare", "heroku"], category: "Software and hosting" },
  { keys: ["stripe", "paypal", "razorpay"], category: "Payment processing fees" },
  { keys: ["uber", "ola", "lyft", "taxi", "cab", "airline", "flight", "train", "bus", "travel"], category: "Travel and meals" },
  { keys: ["wework", "regus", "coworking", "office rent", "rent", "lease"], category: "Rent and utilities" },
  { keys: ["electricity", "water bill", "gas bill", "utility"], category: "Rent and utilities" },
  { keys: ["stationery", "office supplies", "pens", "paper"], category: "Office supplies" },
  { keys: ["consultant", "contractor", "freelancer", "agency", "legal", "lawyer", "accountant"], category: "Professional services" },
  { keys: ["google ads", "facebook ads", "meta ads", "marketing"], category: "Advertising and marketing" },
  { keys: ["zoom", "slack", "notion", "asana", "github", "figma", "subscription", "saas"], category: "Subscriptions" },
  { keys: ["phone", "telecom", "airtel", "jio", "vodafone"], category: "Telecom" },
  { keys: ["laptop", "computer", "hardware", "printer", "equipment"], category: "Equipment" },
  { keys: ["salary", "payroll", "wages"], category: "Payroll" },
  { keys: ["tax", "gst", "vat", "license"], category: "Taxes and licenses" },
  { keys: ["insurance", "premium"], category: "Insurance" },
  { keys: ["bank fee", "bank charges", "neft", "rtgs", "imps"], category: "Bank charges" },
  { keys: ["meal", "lunch", "dinner", "restaurant", "cafe"], category: "Meals and entertainment" },
  { keys: ["training", "course", "udemy", "coursera", "workshop"], category: "Training and development" }
];

// Determine category
let category = null;

for (const map of CATEGORY_MAP) {
  for (const key of map.keys) {
    if (combinedText.includes(key)) {
      category = map.category;
      break;
    }
  }
  if (category) break;
}

// MCC fallback
if (!category && data.mcc) {
  const mcc = data.mcc.toString();
  if (mcc.startsWith("5")) category = "Travel and meals";
  else if (mcc.startsWith("7")) category = "Professional services";
}

// Vendor fallback
if (!category && data.vendor_name) {
  const vendor = norm(data.vendor_name);
  if (vendor.includes("airbnb")) category = "Travel and meals";
  else if (vendor.includes("amazon") || vendor.includes("flipkart")) category = "Office supplies";
}

// FINAL fallback — always filled
if (!category) {
  category = "Other expenses";
}

// Return result
return {
  json: {
    ...data,
    expense_category: category,
    case_id: `INV-${Date.now()}-${Math.random().toString(36).slice(2, 8).toUpperCase()}`,
    processed_at: new Date().toISOString()
  }
};
